    id: "nirmala-sitharaman",
    name: "Nirmala Sitharaman",
    title: "Finance Minister of India",
    category: "She Talks",
    categorySlug: "she-talks",
    image: "/images/personalities/Union-finance-minister-Nirmala-Sitharaman-addresse_1738482069435_1746440750400.avif",
